const item = items[0] ?? { json: {} };
const body = item.json?.body ?? item.json;

const user_id = (body.user_id || '').toString();
const jd_text = (body.jd_text || '').toString().replace(/[\r\n]+/g, ' ').trim();
const user_email = (body.user_email || '').toString();

const errors = [];
if (!user_id) errors.push('Missing user_id');
if (!jd_text || jd_text.length <= 50) errors.push('Invalid job description');

return [{
  json: {
    valid: errors.length === 0,
    errors,
    user_id,
    user_email,
    jd_text,
  },
}];

