const original = items[0].json;

function extractContent(x) {
  if (!x) return '';
  if (typeof x === 'string') return x;
  if (x.choices && x.choices[0]?.message?.content) return x.choices[0].message.content;
  if (x.message?.content) return x.message.content;
  if (x.content?.[0]?.text) return x.content[0].text;
  return '';
}

let raw = extractContent(original);
raw = raw.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();

let extracted;
try {
  extracted = JSON.parse(raw);
} catch (e) {
  throw new Error('Failed to parse Extract JD Data response as JSON. Raw: ' + raw);
}

return [
  {
    json: {
      user_id: original.user_id,
      user_email: original.user_email,
      jd_text: original.jd_text,
      ...extracted,
    },
  },
];

